from flask import Flask, request, jsonify
from flask_oauthlib.client import OAuth2Session
from functools import wraps

app = Flask(__name__)

# Initialize the OAuth2Session with your client ID and secret
oauth = OAuth2Session(client_id='your-client-id', client_secret='your-client-secret')

# Define a decorator to check for valid tokens
def require_oauth(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        # Check if the token exists in the database
        if not oauth.token:
            return jsonify({'error': 'Invalid token'}), 401
        # Call the original function with the validated token
        return func(oauth.token, *args, **kwargs)
    return wrapper

# Define an API endpoint that requires a valid token
@app.route('/api/protected', methods=['GET'])
@require_oauth
def protected():
    # This function will only be called if the token is valid
    return jsonify({'message': 'Hello, world!'})

# Start the Flask app
if __name__ == '__main__':
    app.run(debug=True)